This sample shows how to call CreateAsync.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
Skillsets client = new SearchClient(endpoint, credential).GetSkillsetsClient();

SearchIndexerSkillset skillset = new SearchIndexerSkillset("demoskillset", Array.Empty<SearchIndexerSkill>())
{
    Description = "Extract entities, detect language and extract key-phrases",
    KnowledgeStore = new Search.Documents.Indexes.Models.KnowledgeStore("DefaultEndpointsProtocol=https;AccountName=myStorage;AccountKey=myStorageKey;EndpointSuffix=core.windows.net", new Search.Documents.Indexes.Models.KnowledgeStoreProjection[]
    {
        new Search.Documents.Indexes.Models.KnowledgeStoreProjection
        {
            Tables = {new Search.Documents.Indexes.Models.KnowledgeStoreTableProjectionSelector("Reviews")
            {
                GeneratedKeyName = "ReviewId",
                Source = "/document/Review",
                Inputs = {},
            }, new Search.Documents.Indexes.Models.KnowledgeStoreTableProjectionSelector("Sentences")
            {
                GeneratedKeyName = "SentenceId",
                Source = "/document/Review/Sentences/*",
                Inputs = {},
            }, new Search.Documents.Indexes.Models.KnowledgeStoreTableProjectionSelector("KeyPhrases")
            {
                GeneratedKeyName = "KeyPhraseId",
                Source = "/document/Review/Sentences/*/KeyPhrases",
                Inputs = {},
            }, new Search.Documents.Indexes.Models.KnowledgeStoreTableProjectionSelector("Entities")
            {
                GeneratedKeyName = "EntityId",
                Source = "/document/Review/Sentences/*/Entities/*",
                Inputs = {},
            }},
        },
        new Search.Documents.Indexes.Models.KnowledgeStoreProjection
        {
            Objects = {new Search.Documents.Indexes.Models.KnowledgeStoreObjectProjectionSelector("Reviews")
            {
                GeneratedKeyName = "/document/Review/Id",
                Source = "/document/Review",
            }},
        }
    }),
    EncryptionKey = new SearchResourceEncryptionKey("myUserManagedEncryptionKey-createdinAzureKeyVault", "myKeyVersion-32charAlphaNumericString", "https://myKeyVault.vault.azure.net")
    {
        AccessCredentials = new AzureActiveDirectoryApplicationCredentials("00000000-0000-0000-0000-000000000000")
        {
            ApplicationSecret = "<applicationSecret>",
        },
    },
};
Response<SearchIndexerSkillset> response = await client.CreateAsync(skillset);

